+    #[test]
+    fn cell_diff_display() {
+        let diff = CellDiff {
+            x: 3,
+            y: 7,
+            expected: ModelCell {
+                ch: 'A',
+                style: ModelStyle::default(),
+                link: None,
+            },
+            actual: ModelCell {
+                ch: 'B',
+                style: ModelStyle::default(),
+                link: None,
+            },
+        };
+        let s = format!("{diff}");
+        assert!(s.contains("(3, 7)"));
+        assert!(s.contains("expected 'A'"));
+        assert!(s.contains("got 'B'"));
+    }
