+    #[test]
+    fn cr_lf_sequence() {
+        let mut m = TerminalModel::new(10, 5);
+        m.feed(b"ABC\r\nDEF\r\nGHI");
+        assert_eq!(m.row_text(0), "ABC");
+        assert_eq!(m.row_text(1), "DEF");
