+    #[test]
+    fn multiple_backspaces() {
+        let mut m = TerminalModel::new(10, 3);
+        m.feed(b"ABCDE\x08\x08\x08XY");
+        // After ABCDE cursor at 5. 3 BS → cursor at 2. XY overwrites at 2,3.
+        assert_eq!(m.row_text(0), "ABXYE");
