+    #[test]
+    fn erase_display_all_preserves_cursor() {
+        let mut m = TerminalModel::new(10, 3);
+        m.feed(b"XXXXXXXXXX");
+        m.feed(b"\x1b[1;5H"); // cursor at (4, 0)
