+    #[test]
+    fn put_char_at_full_grid_bottom_right() {
+        let mut m = TerminalModel::new(3, 2);
+        // Position at last cell
+        m.feed(b"\x1b[2;3H"); // row 2, col 3 → (2, 1)
+        m.feed(b"Z");
+        assert_eq!(m.char_at(2, 1), 'Z');
+        // Cursor wraps but stays at bottom
