+        let mut m = TerminalModel::new(5, 2);
+        m.feed(b"\x1b[1mBold\x1b[0m");
+        let dump = m.dump();
+        assert!(dump.contains("Bold"));
+        assert!(dump.contains("Cursor:"));
+        assert!(dump.contains("Style:"));
+    }
