+    fn multiple_sgr_sequences_accumulate() {
+        let mut m = TerminalModel::new(10, 3);
+        m.feed(b"\x1b[1m\x1b[3m\x1b[4mX");
+        let s = m.style_at(0, 0);
+        assert!(s.bold);
+        assert!(s.italic);
