+
+    #[test]
+    fn sgr_zero_in_middle_resets_all() {
+        let mut m = TerminalModel::new(10, 3);
+        m.feed(b"\x1b[1;0;3mX");
+        // SGR 1 sets bold, SGR 0 resets, SGR 3 sets italic
+        let s = m.style_at(0, 0);
+        assert!(!s.bold);
+        assert!(s.italic);
