+    #[test]
+    fn height_1_terminal() {
+        let mut m = TerminalModel::new(10, 1);
+        m.feed(b"Hello");
+        assert_eq!(m.row_text(0), "Hello");
+        m.feed(b"\n"); // LF at bottom, should not move
+        assert_eq!(m.cursor(), (5, 0));
+    }
